namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int TotalRating { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount > 0 ? (double)TotalRating / RatingCount : 0;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Fresh mozzarella, San Marzano tomatoes, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", Description = "A timeless Italian classic with fresh ingredients." },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti until al dente.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra pecorino.", Description = "Creamy Roman pasta made without cream." },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Cumin, Tomato sauce, Heavy cream, Garlic, Ginger, Onion", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Stir in cream and cooked chicken.\n6. Serve over basmati rice.", Description = "Rich and aromatic curry with tender chicken." },
        new Recipe { Id = 4, Title = "Vegetable Samosas", Category = "Indian", Ingredients = "Potatoes, Peas, Cumin seeds, Garam masala, Flour, Oil for frying, Green chilies", Steps = "1. Boil and mash potatoes.\n2. Mix with peas, spices, and chilies.\n3. Make dough from flour, water, and oil.\n4. Roll into circles, cut in half.\n5. Form cones, fill with potato mixture.\n6. Deep fry until golden brown.", Description = "Crispy pastries with spiced potato filling." },
        new Recipe { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheddar cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef, drain fat.\n2. Add taco seasoning and water, simmer.\n3. Warm taco shells in oven.\n4. Dice tomatoes and shred lettuce.\n5. Assemble tacos with beef and toppings.\n6. Serve with sour cream.", Description = "Quick and satisfying weeknight tacos." },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Red onion, Cilantro, Jalapeño, Tomato, Salt", Steps = "1. Halve and pit avocados.\n2. Mash to desired consistency.\n3. Dice onion, tomato, jalapeño, and cilantro.\n4. Fold into avocado.\n5. Add lime juice and salt.\n6. Serve immediately with chips.", Description = "Fresh and zesty avocado dip." },
        new Recipe { Id = 7, Title = "Miso Ramen", Category = "Japanese", Ingredients = "Ramen noodles, Miso paste, Chicken broth, Soft-boiled egg, Chashu pork, Green onions, Nori, Corn", Steps = "1. Simmer chicken broth with miso paste.\n2. Cook ramen noodles according to package.\n3. Prepare soft-boiled eggs (6.5 min).\n4. Slice chashu pork thinly.\n5. Assemble bowls: noodles, broth, toppings.\n6. Garnish with green onions and nori.", Description = "Warming bowl of umami-rich noodle soup." },
        new Recipe { Id = 8, Title = "Teriyaki Salmon", Category = "Japanese", Ingredients = "Salmon fillets, Soy sauce, Mirin, Brown sugar, Garlic, Ginger, Sesame seeds, Rice", Steps = "1. Mix soy sauce, mirin, sugar, garlic, ginger.\n2. Marinate salmon 30 minutes.\n3. Heat a skillet over medium-high.\n4. Sear salmon skin-side up 3 minutes.\n5. Flip and cook 3 more minutes, glazing.\n6. Serve over rice with sesame seeds.", Description = "Sweet and savory glazed salmon." },
    };

    private int _nextId = 9;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRating += stars;
            recipe.RatingCount++;
        }
    }
}

