<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (Recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
                <li class="breadcrumb-item active">@Recipe.Title</li>
            }
        </ol>
    </nav>

    @if (Recipe is null)
    {
        <h1>Recipe Not Found</h1>
        <p>Sorry, we couldn't find that recipe.</p>
    }
    else
    {
        <h1>@Recipe.Title</h1>
        <p class="text-muted">Category: @Recipe.Category</p>

        <div class="row">
            <div class="col-md-4">
                <div class="card mb-4">
                    <div class="card-header"><strong>Ingredients</strong></div>
                    <ul class="list-group list-group-flush">
                        @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                        {
                            <li class="list-group-item">@ingredient</li>
                        }
                    </ul>
                </div>
            </div>

            <div class="col-md-8">
                <div class="card mb-4">
                    <div class="card-header"><strong>Instructions</strong></div>
                    <div class="card-body">
                        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <p>@step</p>
                        }
                    </div>
                </div>
            </div>
        </div>

        <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="my-4 p-3 border rounded">
    <h5>Rate this Recipe</h5>

    @if (!HasRated)
    {
        <div class="star-rating">
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <span class="star @(star <= HoverRating ? "highlighted" : "")"
                      @onmouseover="() => HoverRating = star"
                      @onmouseout="() => HoverRating = 0"
                      @onclick="() => SubmitRating(star)"
                      role="button">
                    @(star <= HoverRating ? "★" : "☆")
                </span>
            }
        </div>
        <p class="text-muted mt-2">Click a star to rate</p>
    }
    else
    {
        <p class="text-success">✓ Thanks! You rated this recipe @SelectedRating out of 5 stars.</p>
    }

    @if (Recipe is not null && Recipe.RatingCount > 0)
    {
        <p class="mt-2">
            Average: <strong>@Recipe.AverageRating.ToString("F1")</strong> / 5
            (@Recipe.RatingCount @(Recipe.RatingCount == 1 ? "rating" : "ratings"))
        </p>
    }
</div>

<style>
    .star-rating .star {
        font-size: 2rem;
        cursor: pointer;
        transition: color 0.2s;
    }
    .star-rating .star.highlighted {
        color: #ffc107;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }
    private int HoverRating { get; set; }
    private int SelectedRating { get; set; }
    private bool HasRated { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(RecipeId);
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        SelectedRating = stars;
        HasRated = true;
        Recipe = RecipeService.GetById(RecipeId);
    }
}

