            <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
        </div>
    }
    else
    {
        <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                <ValidationMessage For="() => Model.Title" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" @bind-Value="Model.Category" class="form-select">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in Categories)
                    {
                        <option value="@cat">@cat</option>
                    }
                    <option value="Other">Other</option>
                </InputSelect>
                <ValidationMessage For="() => Model.Category" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="description" class="form-label">Short Description</label>
                <InputText id="description" @bind-Value="Model.Description" class="form-control" placeholder="A brief description of your recipe" />
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="5" placeholder="One ingredient per line or comma-separated" />
                <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6" placeholder="Step-by-step instructions" />
                <ValidationMessage For="() => Model.Steps" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel Model { get; set; } = new();
    private List<string> Categories { get; set; } = new();
    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Description = Model.Description,
            Ingredients = Model.Ingredients,
            Steps = Model.Steps
        };

        RecipeService.AddRecipe(recipe);
        Submitted = true;
    }

    private void Reset()
    {
        Model = new();
        Submitted = false;
    }
}

